 61	  char t;
 62	  int number_of_events;
 63	  int socket;
 64	  int *is_on;
 65	  int ev_fun;
 66	  int start_valid = 0;
 67	  struct timespec start_time, stop_time, delta_time;
 68	  char *name = "VCD_FUNCTION_ENB_DLSCH_ULSCH_SCHEDULER";
 69	  int stat_mode = 0;
 70	
 71	  for (i = 1; i < n; i++) {
 72	    if (!strcmp(v[i], "-h") || !strcmp(v[i], "--help")) usage();
 73	    if (!strcmp(v[i], "-d"))
 74	      { if (i > n-2) usage(); database_filename = v[++i]; continue; }
 75	    if (!strcmp(v[i], "-ip")) { if (i > n-2) usage(); ip = v[++i]; continue; }
 76	    if (!strcmp(v[i], "-p"))
 77	      { if (i > n-2) usage(); port = atoi(v[++i]); continue; }
 78	    if (!strcmp(v[i], "-e")) { if (i > n-2) usage(); name = v[++i]; continue; }
 79	    if (!strcmp(v[i], "-s")) { stat_mode = 1; continue; }
 80	    usage();
 81	  }
 82	
 83	  if (stat_mode)
 84	    new_thread(stat_thread, NULL);
 85	
 86	  if (database_filename == NULL) {
 87	    printf("ERROR: provide a database file (-d)\n");
 88	    exit(1);
 89	  }
 90	
 91	  database = parse_database(database_filename);
 92	
 93	  load_config_file(database_filename);
 94	
 95	  number_of_events = number_of_ids(database);
 96	  is_on = calloc(number_of_events, sizeof(int));
 97	  if (is_on == NULL) abort();
 98	
 99	  on_off(database, name, is_on, 1);
100	
101	  ev_fun = event_id_from_name(database, name);
102	
103	  socket = connect_to(ip, port);
104	
105	  t = 1;
106	  if (socket_send(socket, &t, 1) == -1 ||
107	      socket_send(socket, &number_of_events, sizeof(int)) == -1 ||
108	      socket_send(socket, is_on, number_of_events * sizeof(int)) == -1)
109	    abort();
110	
111	  OBUF ebuf = {.osize = 0, .omaxsize = 0, .obuf = NULL};
112	
113	  while (1) {
114	    event e;
115	    int on_off;
116	    e = get_event(socket, &ebuf, database);
117	    if (e.type == -1) break;
118	    if (e.type != ev_fun)
119	      { printf("unhandled event %d\n", e.type); continue; }
120	    on_off = e.e[0].i;
121	    if (!stat_mode)
122	      printf("yo %d\n", on_off);
123	    if (on_off == 1) {
124	      start_time = e.sending_time;
125	      start_valid = 1;
126	      continue;
127	    }
128	    if (on_off != 0) { printf("fatal!\n"); abort(); }
129	    if (!start_valid) continue;
130	    start_valid = 0;
131	    stop_time = e.sending_time;
132	    delta_time = time_sub(stop_time, start_time);
133	    if (stat_mode) {
134	      uint64_t v = delta_time.tv_sec * 1000000000UL + delta_time.tv_nsec;
135	      if (count == 0 || v < acc_min) acc_min = v;
136	      if (v > acc_max) acc_max = v;
137	      acc += v;
138	      count++;
139	    } else {
140	      fprintf(stderr, "%ld\n",
141	              delta_time.tv_sec * 1000000000UL + delta_time.tv_nsec);
142	      fflush(stderr);
143	    }
144	  }
145	
146	  return 0;
147	}

