 81	static int interval_empty(struct time *this, int sub,
 82	    struct timespec start, struct timespec end)
 83	{
 84	  int a, b, mid;
 85	  int i;
 86	
 87	  if (this->p[sub].ticksize == 0) return 1;
 88	
 89	  /* look for a tick larger than start and smaller than end */
 90	  a = 0;
 91	  b = this->p[sub].ticksize - 1;
 92	  while (b >= a) {
 93	    mid = (a+b) / 2;
 94	    i = (this->p[sub].tickstart + mid) % this->p[sub].ticksize;
 95	    if (time_cmp(this->p[sub].tick[i], start) < 0) a = mid + 1;
 96	    else if (time_cmp(this->p[sub].tick[i], end) > 0) b = mid - 1;
 97	    else return 0;
 98	  }
 99	  return 1;
100	}
