143	      }
144	    }
145	
146	    widget_dirty(this->g, this->w);
147	
148	    if (pthread_mutex_unlock(&this->lock)) abort();
149	    sleepms(1000 / this->refresh_rate);
150	  }
151	
152	  return 0;
153	}
